def showMenu():
    print("""Vanilla maps overwriter 1.0
    
0. Default maps
1. Halloween maps.
2. Hugging maps.
    """)
    optionId = input("Option id: ")
    os.system("cls")
    
    try:
        return int(optionId)
    except:
        return showMenu()
    
def onMenuOption(optionId : int = -1):
    if optionId == -1 or optionId > 2:
        return
        
    for entry in vanilla_maps:
        if len(entry) < 3:
            continue

        map_code = str(entry[0])
        if optionId == 0:
            code1 = entry[1]
            code2 = ''
            if code1 == '':
                os.remove(f"../config/maps/vanilla/{map_code}.xml")
        elif optionId == 1:
            code1 = entry[1]
            code2 = entry[2]
        elif optionId == 2:
            code1 = entry[1]
            code2 = entry[3]

        if code2 != '':
            content = code2
        elif code1 != '':
            content = code1
        else:
            continue

        file_path = os.path.join("../config/maps/vanilla", f"{map_code}.xml")
        try:
            with open(file_path, "w", encoding="utf-8") as f:
                f.write(content)
            print(f"Modifying the file --> {map_code}.xml")
        except Exception as e:
            print(f"Failed to write the file --> {map_code} : {e}")
    pass
    
if __name__ == "__main__":
    optionId = showMenu()
    onMenuOption(optionId)